UPDATE PI_SERVER_GROUP 
SET NAME = #{name}
WHERE 1 = 1
  AND IDX = #{idx}

mapper.insert:
INSERT INTO pi_server_group_join VALUES (#{group_id}, #{toms_id}, NOW())
ON DUPLICATE KEY UPDATE
REGDATE = NOW();

mapper.delete:
DELETE FROM PI_SERVER_GROUP_JOIN 
WHERE GROUP_IDX IN 

 #{item}

mapper.select:
WITH RECURSIVE CTE AS (SELECT 0 AS LEVEL, 0 AS AP_NO, G.INSA_CODE, G.TEAM_NAME, G.TEAM_NAME AS FULL_TEAM_NM, CAST('pc' AS VARCHAR(50)) AS PARENT, '' AS CONNECTED FROM pi_group G WHERE G.INSA_CODE IN (SELECT INSA_CODE FROM pi_target_service WHERE USER_NO = '#{user_no}' AND ENABLE = 'Y') UNION ALL SELECT CTE.LEVEL + 1 AS LEVEL, 0 AS AP_NO, PG.INSA_CODE, PG.TEAM_NAME, CONCAT(CTE.FULL_TEAM_NM, '>', PG.TEAM_NAME) AS FULL_TEAM_NM, PG.UP_IDX AS PARENT, PG.UP_IDX AS CONNECTED FROM pi_group PG, CTE WHERE PG.UP_IDX = CTE.INSA_CODE ) SELECT CTE.* FROM CTE GROUP BY CTE.INSA_CODE UNION ALL SELECT 99 AS LEVEL, D.AP_NO, D.IDX, D.NAME, '', D.UP_IDX AS PARENT, D.CONNECTED FROM (SELECT U.USER_NO AS IDX, TU.AP_NO, CONCAT(U.USER_NAME,' (',IFNULL(COUNT(TU.TARGET_ID),'0'),')') AS NAME, U.INSA_CODE AS UP_IDX, 1 AS TYPE, IFNULL(TU.TARGET_ID, '') AS CONNECTED FROM CTE, pi_user U LEFT OUTER JOIN pi_target_user TU ON U.USER_NO = TU.USER_NO AND TU.AP_NO != 0 WHERE U.INSA_CODE = CTE.INSA_CODE AND DATE_FORMAT(U.ENDDATE, '%Y-%m-%d') >= DATE_FORMAT(NOW(), '%Y-%m-%d') AND ACC_YN ='Y'
AND U.USER_NO != #{user_no}
GROUP BY U.USER_NAME, U.USER_NO ) D
